async function resolveBuilder (nuxt: Nuxt): Promise<NuxtBuilder> {
  const source = typeof nuxt.options.builder === 'string'
    ? await loadBuilder(nuxt, nuxt.options.builder)
    : nuxt.options.builder

  // Wrap `bundle` so the `build:error` hook fires for any builder, including
  // user-supplied ones, without each caller having to remember to do it.
  return {
    ...source,
    async bundle (nuxt) {
      try {
        await source.bundle(nuxt)
      } catch (error: any) {
        await nuxt.callHook('build:error', error)
        throw error
      }
    },
  }
}

async function register(user: WebAuthnUser) {
  const { creationOptions, attemptId } = await $fetch<RegistrationInitResponse>(registerEndpoint, {
    method: 'POST',
    body: {
      user,
      verify: false,
    },
  })

  const attestationResponse = await startRegistration({
    optionsJSON: creationOptions,
  })
  const verificationResponse = await $fetch<VerifiedRegistrationResponse>(registerEndpoint, {
    method: 'POST',
    body: {
      user,
      attemptId,
      response: attestationResponse,
      verify: true,
    },
  })

  return verificationResponse && verificationResponse.verified
}

function baseAlias (ctx: WebpackConfigContext) {
  ctx.alias = {
    '#app': ctx.options.appDir,
    [basename(ctx.nuxt.options.dir.assets)]: resolve(ctx.nuxt.options.srcDir, ctx.nuxt.options.dir.assets),
    ...ctx.options.alias,
    ...ctx.alias,
  }
  if (ctx.isClient) {
    ctx.alias['nitro/runtime-config'] = resolve(ctx.nuxt.options.buildDir, 'nitro.client.mjs')
    // TODO: remove in v5
    ctx.alias['#internal/nitro'] = resolve(ctx.nuxt.options.buildDir, 'nitro.client.mjs')
    ctx.alias['nitropack/runtime'] = resolve(ctx.nuxt.options.buildDir, 'nitro.client.mjs')
  }
}

async function createdStyleRule (lang: string, test: RegExp, processorLoader: any, ctx: WebpackConfigContext) {
  const styleLoaders = [
    await createPostcssLoadersRule(ctx),
    processorLoader,
  ].filter(Boolean)

  ctx.userConfig.loaders.css.importLoaders =
    ctx.userConfig.loaders.cssModules.importLoaders =
      styleLoaders.length

  const cssLoaders = createCssLoadersRule(ctx, ctx.userConfig.loaders.css)
  const cssModuleLoaders = createCssLoadersRule(ctx, ctx.userConfig.loaders.cssModules)

  return {
    test,
    oneOf: [
      // This matches <style module>
      {
        resourceQuery: /module/,
        use: cssModuleLoaders.concat(styleLoaders),
      },
      // This matches plain <style> or <style scoped>
      {
        use: cssLoaders.concat(styleLoaders),
      },
    ],
  }
}

async () => {
  if (!import.meta.dev) return

  const hub = useRuntimeConfig().hub as ResolvedHubConfig
  if (!hub.db) return
  if (!hub.db.applyMigrationsDuringDev) return

  let db
  try {
    const module = await import('hub:db')
    db = module.db
  } catch (error) {
    console.error('[nuxt:hub] Failed to import hub:db module:', error instanceof Error ? error.message : error)
    console.error('[nuxt:hub] This may happen when using remote bindings before the proxy is initialized.')
    console.error('[nuxt:hub] Migrations will be skipped. Please ensure remote bindings are properly configured.')
    return
  }

  await applyDatabaseMigrations(hub, db)
  await applyDatabaseQueries(hub, db)
}

export function createMarkdownStringifier(options: MDCStringifyOptions = {}) {
  const processor = createStringifyProcessor(options)

  async function stringify(value: any, data: Record<string, any> = {}): Promise<string> {
    const result = await processor.process({ value: JSON.stringify(value) })

    // Stringify front matter returns empty string if no data is provided
    if (Object.keys(data).length) {
      return stringifyFrontMatter(data, result.value as string, options.frontMatter?.options)
    }

    return result.value as string
  }

  return stringify
}

function inferRenderer(cwd: string): RendererName | null {
  // Check existing OG image components for a renderer suffix
  const dirs = [cwd]
  if (existsSync(join(cwd, 'app')))
    dirs.push(join(cwd, 'app'))

  for (const dir of dirs) {
    const components = findOgImageComponents(dir)
    for (const filepath of components) {
      const match = basename(filepath).match(RE_RENDERER_SUFFIX)
      if (match)
        return match[1] as RendererName
    }
  }

  // Fall back to checking installed packages
  const pkg = readPackageJson(cwd)
  if (pkg) {
    const allDeps = { ...pkg.dependencies, ...pkg.devDependencies }
    if (allDeps['@takumi-rs/core'] || allDeps['@takumi-rs/wasm'])
      return 'takumi'
    if (allDeps.satori)
      return 'satori'
  }

  return null
}

async (e) => {
  const runtimeConfig = useRuntimeConfigNuxtRobots(e)
  const { indexable, hints } = getSiteRobotConfig(e)
  const siteConfig = getSiteConfig(e)
  // @ts-expect-error Nuxt typed routes cause excessive type depth with $fetch
  const robotsTxt: string = await e.$fetch('/robots.txt', {
    query: getQuery(e),
  })
  const parsed = validateRobots(parseRobotsTxt(robotsTxt))
  return {
    robotsTxt,
    indexable,
    hints,
    runtimeConfig,
    siteConfig: {
      url: siteConfig.url,
      env: siteConfig.env,
      indexable: siteConfig.indexable,
    },
    validation: {
      errors: parsed.errors,
      warnings: parsed.warnings,
      groups: parsed.groups.length,
      sitemaps: parsed.sitemaps,
    },
  }
}

async function authenticate(userName?: string) {
  const { requestOptions, attemptId } = await $fetch<AuthenticationInitResponse>(authenticateEndpoint, {
    method: 'POST',
    body: {
      verify: false,
      userName,
    },
  })

  const assertionResponse = await startAuthentication({
    optionsJSON: requestOptions,
    useBrowserAutofill,
  })
  const verificationResponse = await $fetch<VerifiedAuthenticationResponse>(authenticateEndpoint, {
    method: 'POST',
    body: {
      attemptId,
      userName,
      response: assertionResponse,
      verify: true,
    },
  })

  return verificationResponse && verificationResponse.verified
}

private transformDynamicImports (source: string): string {
  let transformed = source
  let needsHelperImport = false

  // Transform webpack-style dynamic imports to rollup-compatible ones
  transformed = transformed.replace(DYNAMIC_IMPORT_REPLACE_RE, (match, filename) => {
    needsHelperImport = true
    // Generate a rollup-compatible dynamic import using the module ID
    return `_rollupDynamicImport(${filename}).then`
  })

  // Add import statement at the top if we made any transformations
  if (needsHelperImport && !transformed.includes(HELPER_IMPORT)) {
    transformed = HELPER_IMPORT + transformed
  }

  return transformed
}

function checkScrollPosition() {
  if (!parent.value) {
    return
  }

  const scrollPosition = parent.value.scrollTop + parent.value.clientHeight
  const scrollHeight = parent.value.scrollHeight
  const threshold = 100

  showAutoScroll.value = (scrollHeight - scrollPosition) >= threshold

  // Detect user scrolling up
  if (parent.value.scrollTop < lastScrollTop.value) {
    userScrolledUp.value = true
  } else if ((scrollHeight - scrollPosition) < threshold) {
    userScrolledUp.value = false
  }

  lastScrollTop.value = parent.value.scrollTop
}

async function takeScreenshot(page: Page, selector: string | undefined, options: PageScreenshotOptions): Promise<Buffer> {
  // Remove animations option for Puppeteer (not supported)
  const puppeteerOptions = { ...options }
  if (!isPlaywrightPage(page)) {
    delete (puppeteerOptions as any).animations
  }

  if (selector) {
    if (isPlaywrightPage(page)) {
      return await page.locator(selector).screenshot(puppeteerOptions)
    }
    else {
      // Puppeteer uses page.$(selector) instead of locator
      const element = await (page as any).$(selector)
      if (!element) {
        throw new Error(`Element not found: ${selector}`)
      }
      return await element.screenshot(puppeteerOptions)
    }
  }

  return await page.screenshot(puppeteerOptions)
}

function _calculatePosition (
  to: RouteLocationNormalized,
  from: RouteLocationNormalized,
  savedPosition: ScrollPosition | null,
  defaultHashScrollBehaviour: ScrollBehavior,
): ScrollPosition {
  // By default when the returned position is falsy or an empty object, vue-router will retain the current scroll position
  // savedPosition is only available for popstate navigations (back button)
  if (savedPosition) {
    return savedPosition
  }

  // Scroll to the element specified in the URL hash, if present
  if (to.hash) {
    return {
      el: to.hash,
      top: _getHashElementScrollMarginTop(to.hash),
      behavior: isChangingPage(to, from) ? defaultHashScrollBehaviour : 'instant',
    }
  }

  return {
    left: 0,
    top: 0,
  }
}

async function handleFormatMessage(message) {
  if (!_prettier) {
    const [prettierModule, ...plugins] = await Promise.all([
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/standalone.mjs'),
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/plugins/babel.mjs'),
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/plugins/estree.mjs'),
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/plugins/html.mjs'),
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/plugins/markdown.mjs'),
      import('https://cdn.jsdelivr.net/npm/prettier@3.8.2/plugins/typescript.mjs')
    ])
    _prettier = prettierModule
    _plugins = plugins
  }

  const { options, source } = message
  return _prettier.format(source, {
    parser: 'markdown',
    plugins: _plugins,
    ...options
  })
}

function flushState(log: RequestLogger, state: AccumulatorState): void {
  const flushed = state._flushed
  const data = buildMetadata(state, flushed)

  flushed.toolCalls = state.allToolCalls.length
  flushed.toolCallInputs = state.allToolCallInputs.length
  flushed.toolExecutions = state.toolExecutions.length
  if (data.stepsUsage) flushed.stepsUsage = state.stepsUsage.length
  if (data.models) for (const m of data.models) flushed.models.add(m)

  log.set({ ai: data } as Record<string, unknown>)

  if (state.subscribers.size > 0) {
    notifySubscribers(state, buildMetadata(state))
  }
}

async (event) => {
  const result = credentialsSchema.safeParse(await readBody(event))
  if (!result.success) {
    throw createError({
      statusCode: 400,
      message: `Invalid input, please provide a valid username, and a password must be 'hunter2' for this demo.`
    })
  }

  // Emulate successful registration
  const user = await getUser(result.data.username)

  // Create the sign-in tokens
  const tokens = await createUserTokens(user)

  // Return a success response with the email and the token
  return {
    user,
    token: tokens
  }
}

export function evlog(options: EvlogHonoOptions = {}): MiddlewareHandler {
  return async (c, next) => {
    const { skipped, finish, finishResponse } = integration.start(c, options)
    if (skipped) {
      await next()
      return
    }
    try {
      await next()
      if (shouldDeferEmitForResponse(c.res)) {
        const response = new Response(c.res.body, {
          status: c.res.status,
          headers: c.res.headers,
        })
        return finishResponse(response, { status: response.status })
      }
      await finish({ status: c.res.status })
    } catch (error) {
      await finish({ error: error as Error })
      throw error
    }
  }
}

export function configureHandler(options: NextEvlogOptions): void {
  state.options = options
  state.initialized = true

  // Skip if instrumentation register() already configured the logger.
  // Re-initializing would wipe the global drain.
  if (isLoggerLocked()) return

  // Don't pass drain to initLogger — the global drain fires inside emitWideEvent
  // which doesn't have request/header context. Instead, we call drain ourselves
  // in callEnrichAndDrain after enrich, with full context.
  initLogger({
    enabled: options.enabled,
    env: {
      service: options.service,
      ...options.env,
    },
    pretty: options.pretty,
    silent: options.silent,
    sampling: options.sampling,
    minLevel: options.minLevel,
    stringify: options.stringify,
    _suppressDrainWarning: true,
  })
}

